// src/toolbar.js
import { DraggableNode } from "./draggableNode";

export const PipelineToolbar = () => {
  return (
    <div style={{ padding: "10px" }}>
      <div style={{ marginTop: "20px", display: "flex", flexWrap: "wrap", gap: "10px" }}>
        {/* Original Nodes */}
        <DraggableNode type="inputNode" label="Input" />
        <DraggableNode type="llmNode" label="LLM" />
        <DraggableNode type="textNode" label="Text" />
        <DraggableNode type="outputNode" label="Output" />
        <DraggableNode type="deleteNode" label="Delete" />

        {/* New Demo Nodes */}
        <DraggableNode type="conditionNode" label="Condition" />
        <DraggableNode type="calculatorNode" label="Calculator" />
        <DraggableNode type="fileProcessorNode" label="File Processor" />
        <DraggableNode type="joinNode" label="Join" />
        <DraggableNode type="splitNode" label="Split" />
      </div>
    </div>
  );
};
